#include <stdio.h>
#include <stdint.h>

static uint64_t gcd_uint64(uint64_t a, uint64_t b) {
    while (b) {
        uint64_t t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t N;
        scanf("%llu", &N);
        uint64_t sum = 0;
        uint64_t i = 1;
        while (i <= N) {
            uint64_t q = N / i;
            uint64_t next = N / q;
            sum += q * (next - i + 1);
            i = next + 1;
        }
        uint64_t den = N * N;
        uint64_t g = gcd_uint64(sum, den);
        printf("%llu/%llu\n", sum / g, den / g);
    }
    return 0;
}

